export function exportToDxf(
  elementsById: Record<string, Element>,
  opts?: DxfExportOptions,
): DxfPlanView[] {
  const units: 'mm' | 'm' = opts?.units ?? 'mm';
  const scale = SCALE[units];

  const elements = Object.values(elementsById);
